# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import java.nio.file.{Files, Paths}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsDir = "uploads"

  def serveFile(filename: String) = Action { implicit request: Request[AnyContent] =>
    try {
      val sanitizedPath = sanitizePath(filename)
      val filePath = s"$uploadsDir/$sanitizedPath"
      val file = new File(filePath)
      
      if (!file.exists()) {
        NotFound(s"File not found: $filename")
      } else if (file.isDirectory) {
        BadRequest("Cannot serve directory")
      } else {
        val canonicalPath = file.getCanonicalPath
        val uploadsCanonicalPath = new File(uploadsDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(uploadsCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val source = Source.fromFile(filePath)
          try {
            val content = source.mkString
            val contentType = Files.probeContentType(Paths.get(filePath))
            Ok(content).as(if (contentType != null) contentType else "application/octet-stream")
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def serveFileFromSubdir(subdir: String, filename: String) = Action { implicit request: Request[AnyContent] =>
    try {
      val sanitizedSubdir = sanitizePath(subdir)
      val sanitizedFilename = sanitizePath(filename)
      val filePath = s"$uploadsDir/$sanitizedSubdir/$sanitizedFilename"
      val file = new File(filePath)
      
      if (!file.exists()) {
        NotFound(s"File not found: $subdir/$filename")
      } else if (file.isDirectory) {
        BadRequest("Cannot serve directory")
      } else {
        val canonicalPath = file.getCanonicalPath
        val uploadsCanonicalPath = new File(uploadsDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(uploadsCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val source = Source.fromFile(filePath)
          try {
            val content = source.mkString
            val contentType = Files.probeContentType(Paths.get(filePath))
            Ok(content).as(if (contentType != null) contentType else "application/octet-stream")
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def listFiles(subdir: Option[String] = None) = Action { implicit request: Request[AnyContent] =>
    try {
      val dirPath = subdir match {
        case Some(dir) => s"$uploadsDir/${sanitizePath(dir)}"
        case None => uploadsDir
      }
      
      val directory = new File(dirPath)
      
      if (!directory.exists()) {
        NotFound("Directory not found")
      } else if (!directory.isDirectory) {
        BadRequest("Not a directory")
      } else {
        val canonicalPath = directory.getCanonicalPath
        val uploadsCanonicalPath = new File(uploadsDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(uploadsCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val files = directory.listFiles()
          if (files != null) {
            val fileList = files.map { file =>
              Map(
                "name" -> file.getName,
                "type" -> (if (file.isDirectory) "directory" else "file"),
                "size" -> file.length().toString
              )
            }.toList
            Ok(play.api.libs.json.Json.toJson(fileList))
          } else {
            Ok(play.api.libs.json.Json.arr())
          }
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error listing files: ${e.getMessage}")
    }
  }

  def downloadFile(filename: String) = Action { implicit request: Request[AnyContent] =>
    try {
      val sanitizedPath = sanitizePath(filename)
      val filePath = s"$uploadsDir/$sanitizedPath"
      val file = new File(filePath)
      
      if (!file.exists()) {
        NotFound(s"File not found: $filename")
      } else if (file.isDirectory) {
        BadRequest("Cannot download directory")
      } else {
        val canonicalPath = file.getCanonicalPath
        val uploadsCanonicalPath = new File(uploadsDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(uploadsCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val source = Source.fromFile(filePath)
          try {
            val content = source.mkString
            val contentType = Files.probeContentType(Paths.get(filePath))
            Ok(content)
              .as(if (contentType != null) contentType else "application/octet-stream")
              .withHeaders(
                "Content-Disposition" -> s"attachment; filename=${file.getName}"
              )
          } finally {
            source.close()
          }
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error downloading file: ${e.getMessage}")
    }
  }

  private def sanitizePath(path: String): String = {
    path.replaceAll("\\.\\.", "").replaceAll("^/+", "")
  }
}